SELECT b.homepage_id, b.apply_idx, b.excursions_idx, b.agency_name, b.agency_tel, b.agency_address, b.applicant_name, b.applicant_tel, b.applicant_email, b.age, b.guide_name, b.guide_tel, a.start_date, a.start_time, a.end_date, a.end_time, b.personnel,b. apply_state, ip, b.remarks, b.add_date, b.apply_id, b.applicant_member_id, b.member_key, b.self_info_yn, (SELECT COUNT(*) FROM BLACKLIST WHERE HOMEPAGE_ID = b.HOMEPAGE_ID AND MEMBER_KEY = b.MEMBER_KEY AND INSTR(BLACK_TYPE, '40') != 0) as isBlackList FROM CMS_EXCURSIONS a, CMS_EXCURSIONS_APPLY b WHERE a.homepage_id = b.homepage_id AND a.excursions_idx = b.excursions_idx AND b.homepage_id = #{homepage_id}
AND b.excursions_idx = #{excursions_idx}
AND a.START_DATE >= #{plan_date} AND a.END_DATE <= #{plan_date}
ORDER BY a.add_date

SELECT b.homepage_id, b.apply_idx, b.excursions_idx, b.agency_name, b.agency_tel, b.agency_address, b.applicant_name, b.applicant_tel, b.applicant_email, b.age, b.guide_name, b.guide_tel, a.start_date, a.start_time, a.end_date, a.end_time, b.personnel,b. apply_state, ip, b.remarks, b.add_date, b.apply_id, b.applicant_member_id, b.member_key, b.self_info_yn FROM CMS_EXCURSIONS a, CMS_EXCURSIONS_APPLY b WHERE a.homepage_id = b.homepage_id AND a.excursions_idx = b.excursions_idx AND b.homepage_id = #{homepage_id}
AND b.START_DATE >= #{start_date} AND b.END_DATE <= #{end_date}
ORDER BY a.start_date ASC, a.start_time ASC, b.apply_idx ASC

